import React from "react";

import Layout from "../layouts/default";
import PageHeader from "../components/PageHeader";
import PageContent from "../components/Content";
import SearchBar from "../components/SearchBar";
import CommandsList from "../components/CommandsList";
import fetchCommands from "../utils/fetchCommands";

let cachedCommands;

export default class Commands extends React.Component {
    constructor(props) {
        super(props);

        this.state = {
            noResults: false,
            commands: [],
        };

        this.filterCommands = this.filterCommands.bind(this);
    }

    filterCommands() {
        let input = document.getElementById("commandSearchBar");
        let filter = input.value.toLowerCase();
        let table = document.getElementById("commandsTable");

        let tr = table.getElementsByClassName("command");

        for (let i = 0; i < tr.length; i++) {
            let commands = tr[i].getElementsByTagName("td")[0];
            let descriptions = tr[i].getElementsByTagName("td")[1];
            if (commands || descriptions) {
                if (commands.innerHTML.toLowerCase().indexOf(filter) > -1 || descriptions.innerHTML.toLowerCase().indexOf(filter) > -1) {
                    tr[i].style.display = "";
                } else {
                    tr[i].style.display = "none";
                }
            }
        }

        tr = Array.from(tr);
        let hiddenRows = tr.filter(row => row.style.display !== "none");
        if (hiddenRows.length) {
            this.setState({ noResults: false });
        } else {
            this.setState({ noResults: true });
        }
    }

    componentDidMount() {
        if (cachedCommands) {
            this.setState({
                commands: cachedCommands
            });
        } else {
            fetchCommands().then(fetchedCommands => {
                cachedCommands = fetchedCommands;

                this.setState({ commands: fetchedCommands });
            }).catch(console.error);
        }
    }

    render() {
        return (
            <Layout
                title="Commands"
                description="Check out all the commands Bastion's got and use it to make your Discord experience great!"
                image="https://resources.bastionbot.org/og/6dd19a650f52442ba441635325d952f6.jpg"
            >
                <PageHeader />

                <PageContent>
                    <div css={{
                        textAlign: "center",
                        marginBottom: 50,
                    }}>
                        <h1>Commands</h1>
                        <p>Check out the list of commands that you can use with Bastion.</p>
                        <p>The default prefix of Bastion is <code>#!</code></p>
                        <SearchBar onKeyUp={ this.filterCommands } />
                    </div>
                    <CommandsList commands={ this.state.commands } noResults={ this.state.noResults } />
                </PageContent>
            </Layout>
        );
    };
}
